export function renderCombinedProgress(
	orchestratorActivity: OrchestratorActivity,
	specialistName: string,
	feedState: ActivityFeedState,
	goal?: string,
): string {
	advanceSpinner();

	if (feedState.errored) {
		const msg = feedState.errorMessage ?? "Unknown error";
		const retryCount = (feedState as any).retryCount;
		if (retryCount) {
			const reason = (feedState as any).retryReason || msg;
			return `⠇ Retry ${retryCount}/3: ${reason}`;
		}
		return `✗ Step failed: ${msg}`;
	}

	const lines: string[] = [];

	// Show subagent's parsed step progress when available, otherwise orchestrator's
	const showFeedProgress = feedState.steps.length > 0;
	const feedTotal = showFeedProgress ? feedState.steps.length : 0;
	const feedCompleted = showFeedProgress
		? feedState.steps.filter((s) => s.completed).length
		: 0;
	const orcTotal = orchestratorActivity.steps.length;

	if (goal) {
		lines.push(`◆ ${goal}`);
	} else if (feedState.goal) {
		lines.push(`◆ ${feedState.goal}`);
	}

	if (showFeedProgress) {
		const dots = feedState.steps.filter((s) => s.completed).map(() => "●").join("");
		lines.push(`${dots} [${feedCompleted}/${feedTotal}]`);
	}

	for (let i = 0; i < orcTotal; i++) {
		const step = orchestratorActivity.steps[i];
		const isCurrent = i === orchestratorActivity.currentStep;
		const isPending = !step.completed && !isCurrent;

		if (step.completed) {
			const duration = step.startTime && step.endTime
				? formatDuration(step.endTime - step.startTime)
				: "";
			lines.push(`✓ ${step.label}${duration ? ` (${duration})` : ""}`);
		} else if (isCurrent) {
		// Show feed state steps with their tool call substeps
		if (feedState.steps.length > 0 && feedState.currentStep >= 0) {
			for (let fi = 0; fi < feedState.steps.length; fi++) {
				const fs = feedState.steps[fi];
				const isFeedCurrent = fi === feedState.currentStep;
				const spinner = SPINNER_FRAMES[getSpinnerIndex() % SPINNER_FRAMES.length];

				if (fs.completed) {
					const dur = fs.startTime && fs.endTime
						? " (" + formatDuration(fs.endTime - fs.startTime) + ")"
						: "";
					lines.push(`  ✓ ${fs.label}${dur}`);
				} else if (isFeedCurrent) {
					lines.push(`  ${spinner} ${fs.label}...`);
				} else {
					lines.push(`  ○ ${fs.label}`);
				}

				// Show substeps (tool calls) for this feed step
				if (fs.substeps.length > 0) {
					// Show recent substeps
					const visibleSubs = fs.substeps.slice(-MAX_FEED_SUBSTEPS);
					const hiddenCount = fs.substeps.length - visibleSubs.length;
					if (hiddenCount > 0) {
						lines.push(`    ... +${hiddenCount} more`);
					}
					for (const sub of visibleSubs) {
						if (sub.completed) {
							const subDur = sub.startTime && sub.endTime
								? " (" + formatDuration(sub.endTime - sub.startTime) + ")"
								: "";
							lines.push(`    ✓ ${sub.label}${subDur}`);
						} else {
							lines.push(`    ${spinner} ${sub.label}...`);
						}
					}
				}
			}
		} else {
			lines.push(`  ${SPINNER_FRAMES[getSpinnerIndex() % SPINNER_FRAMES.length]} Working...`);
		}
		} else if (isPending) {
			lines.push(`○ ${step.label}`);
		}
	}

	return lines.join("\n");
}
